from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent sentence.
    """
    if not triples:
        return ""

    # Identify the main building subject (most common subject)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get) if subject_counts else None

    if not main_subject:
        return ""

    # Build maps for main subject and related subjects
    main_info = {}
    related_subjects = {}
    related_info = {}  # Store additional info about related subjects

    for t in triples:
        if t.subject == main_subject:
            main_info[t.predicate] = t.object
        else:
            # Track related subjects
            if t.predicate in ['country', 'isPartOf', 'state', 'region']:
                related_subjects[t.predicate] = t.object
            else:
                # Store info about related subjects (e.g., country's capital, leader)
                if t.subject not in related_info:
                    related_info[t.subject] = {}
                related_info[t.subject][t.predicate] = t.object

    # Build the sentence
    sentence_parts = []

    # Start with building name and type
    building_type = main_info.get('buildingType', '')
    if building_type:
        sentence_parts.append(f"{main_subject}, a {building_type}")
    else:
        sentence_parts.append(main_subject)

    # Add architect information
    if 'architect' in main_info:
        sentence_parts.append(f"designed by {main_info['architect']}")

    # Add architectural style
    if 'architecturalStyle' in main_info:
        sentence_parts.append(f"featuring {main_info['architecturalStyle']} architecture")

    # Add location information (chain hierarchies)
    location_text = []
    if 'location' in main_info:
        location_text.append(main_info['location'])

    if related_subjects:
        if 'isPartOf' in related_subjects:
            location_text.append(related_subjects['isPartOf'])
        if 'state' in related_subjects:
            location_text.append(related_subjects['state'])
        if 'region' in related_subjects:
            location_text.append(related_subjects['region'])
        if 'country' in related_subjects:
            location_text.append(related_subjects['country'])

    if location_text:
        sentence_parts.append(f"located in {', '.join(location_text)}")

    # Add related subject info (e.g., country's capital, leader)
    country = related_subjects.get('country', None)
    if country and country in related_info:
        if 'capital' in related_info[country]:
            sentence_parts.append(f"where the capital is {related_info[country]['capital']}")
        if 'leader' in related_info[country]:
            sentence_parts.append(f"with {related_info[country]['leader']} as leader")
        if 'governingBody' in related_info[country]:
            sentence_parts.append(f"governed by {related_info[country]['governingBody']}")

    # Add physical attributes
    if 'height' in main_info:
        sentence_parts.append(f"standing {main_info['height']} tall")

    if 'floorCount' in main_info:
        sentence_parts.append(f"with {main_info['floorCount']} floors")

    if 'numberOfRooms' in main_info:
        sentence_parts.append(f"containing {main_info['numberOfRooms']} rooms")

    if 'bedCount' in main_info:
        sentence_parts.append(f"offering {main_info['bedCount']} beds")

    if 'floorArea' in main_info:
        sentence_parts.append(f"covering {main_info['floorArea']}")

    # Add dates
    if 'completionDate' in main_info:
        sentence_parts.append(f"completed in {main_info['completionDate']}")
    elif 'yearOfConstruction' in main_info:
        sentence_parts.append(f"built in {main_info['yearOfConstruction']}")
    elif 'buildingStartDate' in main_info:
        sentence_parts.append(f"construction began in {main_info['buildingStartDate']}")
    elif 'inaugurationDate' in main_info:
        sentence_parts.append(f"inaugurated on {main_info['inaugurationDate']}")

    # Add owner/developer/tenant info
    if 'owner' in main_info:
        sentence_parts.append(f"owned by {main_info['owner']}")
    if 'developer' in main_info:
        sentence_parts.append(f"developed by {main_info['developer']}")
    if 'tenant' in main_info:
        sentence_parts.append(f"tenanted by {main_info['tenant']}")
    if 'currentTenants' in main_info:
        sentence_parts.append(f"occupied by {main_info['currentTenants']}")

    # Add cost information
    if 'cost' in main_info:
        sentence_parts.append(f"at a cost of {main_info['cost']}")

    # Add address
    if 'address' in main_info:
        sentence_parts.append(f"addressed at {main_info['address']}")

    # Add former name
    if 'formerName' in main_info:
        sentence_parts.append(f"formerly known as {main_info['formerName']}")

    # Add other attributes
    if 'website' in main_info:
        sentence_parts.append(f"website {main_info['website']}")
    if 'postalCode' in main_info:
        sentence_parts.append(f"postal code {main_info['postalCode']}")
    if 'NationalRegisterOfHistoricPlacesReferenceNumber' in main_info:
        sentence_parts.append(f"registered as {main_info['NationalRegisterOfHistoricPlacesReferenceNumber']}")

    # Add architecture (alternative to architecturalStyle)
    if 'architecture' in main_info and 'architecturalStyle' not in main_info:
        sentence_parts.append(f"following {main_info['architecture']}")

    # Join the sentence parts into a coherent complex sentence
    if len(sentence_parts) == 1:
        sentence = sentence_parts[0]
    elif len(sentence_parts) == 2:
        sentence = f"{sentence_parts[0]}, {sentence_parts[1]}"
    else:
        # Create a more natural complex sentence structure
        first_part = sentence_parts[0]
        middle_parts = sentence_parts[1:-1]
        last_part = sentence_parts[-1]
        sentence = f"{first_part}, {', '.join(middle_parts)}, and {last_part}"

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

# EVOLVE-BLOCK-END

